	private static final class RunQueryPlanState extends ThemeQueryPlanRunBenchmark.BaseState {

		private OptimizedPlanSnapshot optimizedPlanSnapshot() {
			try (LmdbBenchmarkQueryPlan plan = preparePlan()) {
				return new OptimizedPlanSnapshot(plan.optimizedPlan(), plan.optimizedDiagnostics());
			}
		}

		private ExplainedPlanSnapshot explainedPlanSnapshot() {
			var tupleQuery = connection.prepareTupleQuery(query);
			tupleQuery.setIncludeInferred(false);
			tupleQuery.setMaxExecutionTime(60);
			Explanation explanation = LmdbBenchmarkQueryPlan.withCascadesOptimizationTimeout(60,
					() -> tupleQuery.explain(Explanation.Level.Optimized));
			TupleExpr optimized = (TupleExpr) explanation.tupleExpr();
			return new ExplainedPlanSnapshot(explanation.toString(), new TupleExprIRRenderer().render(optimized),
					optimized.getStringMetricPlanned("optimizer.cascadesCompleteness"),
					optimized.getStringMetricPlanned("optimizer.cascadesDiagnostics"), optimized);
		}

		private void disableTelemetryTeardown() {
			query = null;
		}
	}

	private static void assertBefore(String rendered, Pattern first, String second, String description) {
		var matcher = first.matcher(rendered);
		assertTrue(matcher.find(), "Missing finite value relation while checking: " + description + "\n" + rendered);
		int secondIndex = rendered.indexOf(second);
		assertTrue(secondIndex > matcher.start(),
				description + ": expected finite value relation before `" + second + "`\n" + rendered);
	}

	private static void assertNoHugeContextualInnerJoin(String plan) {
		var matcher = CONTEXTUAL_INNER_JOIN_ROWS.matcher(plan);
		while (matcher.find()) {
			double rows = Double.parseDouble(matcher.group(1));
			if ("K".equals(matcher.group(2))) {
				rows *= 1_000.0d;
			} else if ("M".equals(matcher.group(2))) {
				rows *= 1_000_000.0d;
			} else if ("B".equals(matcher.group(2))) {
				rows *= 1_000_000_000.0d;
			}
			assertTrue(rows <= MAX_SAFE_CONTEXTUAL_INNER_JOIN_ROWS,
					"A contextual finite lookup was multiplied into an unsafe global surface: " + matcher.group()
							+ "\n" + plan);
		}
	}

	private static void assertExactFiniteDomain(TupleExpr optimized, String variable, Set<String> expectedValues) {
		List<Set<String>> matchingDomains = new ArrayList<>();
		optimized.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(BindingSetAssignment node) {
				if (!node.getBindingNames().contains(variable)) {
					return;
				}
				Set<String> values = new LinkedHashSet<>();
				for (BindingSet bindingSet : node.getBindingSets()) {
					if (bindingSet.hasBinding(variable)) {
						values.add(bindingSet.getValue(variable).stringValue());
					}
				}
				matchingDomains.add(Set.copyOf(values));
			}
		});
		assertEquals(List.of(expectedValues), matchingDomains,
				"Expected one exact finite domain for ?" + variable + " in the optimized algebra\n" + optimized);
	}

	private static void assertFiniteCodeLookupJoin(TupleExpr optimized, String plan) {
		List<Join> matchingJoins = new ArrayList<>();
		optimized.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(Join node) {
				boolean finiteThenCode = isFiniteCodeRelation(node.getLeftArg()) && isMedicalCodePattern(node.getRightArg());
				boolean codeThenFinite = isMedicalCodePattern(node.getLeftArg()) && isFiniteCodeRelation(node.getRightArg());
				if (finiteThenCode || codeThenFinite) {
					matchingJoins.add(node);
				}
				super.meet(node);
			}
		});
		assertEquals(1, matchingJoins.size(),
				"Expected one direct join between the finite code relation and the medical-code access\n" + plan);

		Join join = matchingJoins.getFirst();
		StatementPattern codePattern = isMedicalCodePattern(join.getLeftArg())
				? (StatementPattern) join.getLeftArg()
				: (StatementPattern) join.getRightArg();
		assertAll(
				() -> assertTrue(isFiniteCodeRelation(join.getLeftArg()),
						"The finite code relation must be the selected-prefix input\n" + plan),
				() -> assertTrue(isMedicalCodePattern(join.getRightArg()),
						"The condition-code access must be the bound lookup input\n" + plan),
				() -> assertFalse("hash".equals(join.getStringMetricPlanned("optimizer.joinAlgorithmHint")),
						"The finite relation and code access must not use a full-scan hash join\n" + plan),
				() -> assertEquals("lmdb-finite-binding-lookup",
						codePattern.getStringMetricPlanned("plannedEstimateSource"),
						"The code access must be costed as finite bound lookups\n" + plan),
				() -> assertEquals(2.0d, codePattern.getDoubleMetricPlanned("plannedDistinctLookupBindings"), 0.0d,
						"The two exact code values must produce two distinct lookups\n" + plan),
				() -> assertEquals(2.0d, codePattern.getDoubleMetricPlanned("plannedRepeatedInvocations"), 0.0d,
						"The code access must open once for each exact code value\n" + plan));
	}

	private static boolean isFiniteCodeRelation(TupleExpr tupleExpr) {
		return tupleExpr instanceof BindingSetAssignment assignment && assignment.getBindingNames().contains("code");
	}

	private static boolean isMedicalCodePattern(TupleExpr tupleExpr) {
		return tupleExpr instanceof StatementPattern pattern
				&& pattern.getPredicateVar().hasValue()
				&& "http://example.com/theme/medical/code"
						.equals(pattern.getPredicateVar().getValue().stringValue());
	}

	private static boolean reopensFiniteLookupPerObservation(TupleExpr optimized, String finiteVariable,
			String observationPredicateIri, String valuePredicateIri) {
		boolean[] found = { false };
		optimized.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(Join node) {
				found[0] |= "JoinIterator".equals(node.getAlgorithmName())
						&& containsPredicate(node.getLeftArg(), observationPredicateIri)
						&& containsFiniteBinding(node.getRightArg(), finiteVariable)
						&& containsPredicate(node.getRightArg(), valuePredicateIri);
				super.meet(node);
			}
		});
		return found[0];
	}

	private static boolean containsFiniteBinding(TupleExpr tupleExpr, String variable) {
		boolean[] found = { false };
		tupleExpr.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(BindingSetAssignment node) {
				found[0] |= node.getBindingNames().contains(variable);
			}
		});
		return found[0];
	}

	private static boolean containsPredicate(TupleExpr tupleExpr, String predicateIri) {
		boolean[] found = { false };
		tupleExpr.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(StatementPattern node) {
				found[0] |= node.getPredicateVar().hasValue()
						&& predicateIri.equals(node.getPredicateVar().getValue().stringValue());
			}
		});
		return found[0];
	}

	private static int occurrences(String value, Pattern pattern) {
		int count = 0;
		var matcher = pattern.matcher(value);
		while (matcher.find()) {
			count++;
		}
		return count;
	}

